// Extract message from Telegram update
const data = $input.item.json;
const message = (data.message?.text || '').toLowerCase().trim();
const chatId = data.message?.chat?.id?.toString() || '';
const firstName = data.message?.chat?.first_name || 'there';
const updateId = data.update_id?.toString() || '';

// Keywords
const trialKeywords = ['free trial', 'free plan', 'trial', 'try free', 'demo'];
const doneKeywords = ['done', 'completed', 'done!', 'finished', 'working'];

const isTrialRequest = trialKeywords.some(k => message.includes(k));
const isDoneReply = doneKeywords.some(k => message.includes(k));

return {
  json: {
    chatId,
    firstName,
    message,
    updateId,
    is_trial_request: isTrialRequest,
    is_done_reply: isDoneReply
  }
};

// Count pending (uncredited) surveys for this customer
const chatId = $('Parse Message').first().json.chatId;

return { json: { chatId } };

// No surveys completed yet
const firstName = $('Parse Message').first().json.firstName;

const message = `⏳ You no complete any survey yet.

To get your free proxy:
1. Click the survey link I sent earlier
2. Complete the survey
3. Come back and tell me "done"

You fit do as many surveys as you want — each one give you 2 more hours!
Come back when you don complete at least one survey. 👋`;

return { json: { message } };

// Calculate hours and check cap
const surveyCountRaw = $input.item.json.survey_count;
const surveyCount = parseInt(surveyCountRaw, 10);

const MAX_SURVEYS = 12;
const HOURS_PER_SURVEY = 2;
const MAX_HOURS = MAX_SURVEYS * HOURS_PER_SURVEY; // 24

const cappedCount = Math.min(surveyCount, MAX_SURVEYS);
const totalHours = cappedCount * HOURS_PER_SURVEY;
const hitCap = surveyCount >= MAX_SURVEYS;

return {
  json: {
    survey_count: surveyCount,
    total_hours: totalHours,
    hit_cap: hitCap,
    port: 8001 + Math.floor(Math.random() * 99) // Random port 8001-8100 — TODO: query active ports for availability
  }
};

// Generate trial credentials
const crypto = require('crypto');

const chatId = $('Parse Message').first().json.chatId;
const totalHours = parseInt($input.item.json.total_hours);
const port = parseInt($input.item.json.port);

const userId = 'trial_' + crypto.randomBytes(4).toString('hex');
const password = crypto.randomBytes(8).toString('base64').replace(/[+/=]/g, '').substring(0, 16);

const expiresAt = new Date(Date.now() + totalHours * 60 * 60 * 1000).toISOString();
const expiresDisplay = new Date(Date.now() + totalHours * 60 * 60 * 1000)
  .toLocaleString('en-GB', { hour: '2-digit', minute: '2-digit', day: '2-digit', month: 'short' });

const remaining = Math.max(0, 12 - Math.floor(totalHours / 2));

return {
  json: {
    chatId,
    user_id: userId,
    password,
    port,
    expires_at: expiresAt,
    expires_display: expiresDisplay,
    total_hours: totalHours,
    remaining_surveys: remaining,
    survey_count: Math.floor(totalHours / 2)
  }
};

// Compose success message
const c = $input.item.json;
const totalHours = parseInt(c.total_hours);
const remaining = Math.max(0, 12 - parseInt(c.survey_count));
const hitCap = parseInt(c.survey_count) >= 12;

let hoursLine = `${totalHours} hours`;
if (hitCap) hoursLine = '24 hours (maximum!)';

const message = `🎉 Your proxy don ready!

━━━━━━━━━━━━━━━━━━
🌐 BUNCHE TRIAL PROXY
━━━━━━━━━━━━━━━━━━

🔗 IP: proxy.bunche.ng
🔌 Port: ${c.port}
👤 User: ${c.user_id}
🔑 Pass: ${c.password}

⏰ Duration: ${hoursLine}
📊 Surveys completed: ${c.survey_count}/12

⚠️ Shared proxy — other trial users share this IP.
For private/production use, upgrade to a paid plan.

💡 Want more time? You fit do up to ${remaining} more surveys!
Just come back and tell me "done" again when you ready. 😊`;

return { json: { message, chatId: c.chatId } };

// Slots busy message
const chatId = $('Parse Message').first().json.chatId;
const message = `⚠️ All trial slots busy for now.

Our free trial proxy dey full — e go free up within 30 minutes.
Make you no go anywhere o! As e free, I go send you your proxy details. 😊

Or if you no want wait, you fit order paid proxy now:
• ISP UK: ₦6,500/mo
• Residential: from ₦1,950/GB

Just tell me "I want to order"!`;

return { json: { message, chatId } };
